// ---------------------------------------------------------------------------
// Interface and types
// ---------------------------------------------------------------------------

/// Verdict from L1 scanning.
#[derive(Debug, Clone, PartialEq)]
pub enum L1Verdict {
    Allow,
    Block(L1Block),
}

/// Details for a blocked request.
#[derive(Debug, Clone, PartialEq)]
pub struct L1Block {
    pub reason: String,
    pub message_index: usize,
    pub role: Role,
    pub score: f64,
}

/// Per-message L1 score. Collected for ALL untrusted messages regardless of
/// whether the first breach triggers a block verdict.
#[derive(Debug, Clone, PartialEq)]
pub struct L1MessageScore {
    pub message_index: usize,
    pub role: Role,
    /// Raw SVM margin (bias + sum of n-gram weights). Unbounded.
    pub score: f64,
    /// Calibrated probability [0.0, 1.0] via sigmoid scaling.
    /// Compatible with L3/L4 scores for verdict processor combination.
    pub calibrated: f32,
    /// Which specialist produced this score (None = generalist).
    pub specialist_name: Option<String>,
}

/// Full L1 result: verdict plus per-message scores for all scanned messages.
/// The verdict processor needs scores from ALL messages, not just the first breach.
#[derive(Debug, Clone, PartialEq)]
pub struct L1Result {
    pub verdict: L1Verdict,
    pub per_message_scores: Vec<L1MessageScore>,
}

/// Scans inbound messages with a lightweight n-gram classifier.
pub trait L1Scanner: Send + Sync {
    fn scan(&self, messages: &[Message], config: &L1Config) -> L1Result;
}

// ---------------------------------------------------------------------------
// Sigmoid calibration
// ---------------------------------------------------------------------------

/// Sigmoid steepness parameter. Derived empirically from 54K eval corpus:
/// - Benign median score: -4.39, Malicious median: 1.82
/// - At A=0.6: P(benign_median)=0.07, P(mal_median)=0.75, P(strong_mal_7.5)=0.99
/// - Maps score=0 (SVM boundary) to P=0.5 exactly.
const SIGMOID_A: f64 = 0.6;

/// Sigmoid offset. Zero because the SVM is already centered at the
/// decision boundary (threshold=0.0 in eval config).
const SIGMOID_B: f64 = 0.0;

/// Convert a raw SVM margin to a calibrated probability [0.0, 1.0].
///
/// `P = 1.0 / (1.0 + exp(-A * (score + B)))`
///
/// Calibration derived from 54K eval corpus (12,550 malicious, 41,555 benign):
/// | Raw Score | Calibrated | Interpretation |
/// |-----------|------------|----------------|
/// | -7.0      | 0.015      | Very confident benign |
/// | -4.4      | 0.070      | Benign (median benign score) |
/// |  0.0      | 0.500      | Decision boundary |
/// |  1.8      | 0.749      | Malicious (median malicious score) |
/// |  5.0      | 0.953      | Strong malicious |
/// |  7.5      | 0.989      | Very confident malicious |
pub fn calibrate_score(raw_score: f64) -> f32 {
    let p = 1.0 / (1.0 + (-SIGMOID_A * (raw_score + SIGMOID_B)).exp());
    p as f32
}

// ---------------------------------------------------------------------------
// Scoring
// ---------------------------------------------------------------------------

/// Which n-gram analyzer a specialist uses. Mirrors sklearn's analyzer parameter.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum NgramAnalyzer {
    /// `char_wb`: character n-grams with word-boundary padding.
    /// Each word gets wrapped with spaces: "hello" → " hello ".
    CharWb,
    /// `char`: raw character n-grams with no word-boundary padding.
    /// Better for gibberish/GCG suffixes that have no real word boundaries.
    Char,
    /// `word`: whitespace-tokenized word n-grams.
    /// Better for phrase-level signals like "ignore previous instructions".
    Word,
}

/// Extract unique n-grams from text using the specified analyzer and range.
fn extract_ngrams_with(text: &str, analyzer: NgramAnalyzer, ngram_range: (usize, usize)) -> Vec<String> {
    match analyzer {
        NgramAnalyzer::CharWb => extract_char_wb_ngrams(text, ngram_range),
        NgramAnalyzer::Char => extract_char_ngrams(text, ngram_range),
        NgramAnalyzer::Word => extract_word_ngrams(text, ngram_range),
    }
}

/// `char_wb` analyzer: character n-grams with word-boundary space padding.
/// Mirrors sklearn's `CountVectorizer(analyzer='char_wb', binary=True)`.
fn extract_char_wb_ngrams(text: &str, ngram_range: (usize, usize)) -> Vec<String> {
    let lower = text.to_lowercase();
    let mut seen = std::collections::HashSet::new();
    let mut ngrams = Vec::new();

    for word in lower.split_whitespace() {
        let padded = format!(" {word} ");
        let bytes = padded.as_bytes();
        for n in ngram_range.0..=ngram_range.1 {
            if bytes.len() < n {
                continue;
            }
            for window in bytes.windows(n) {
                if let Ok(ngram) = std::str::from_utf8(window) {
                    let s = ngram.to_string();
                    if seen.insert(s.clone()) {
                        ngrams.push(s);
                    }
                }
            }
        }
    }

    ngrams
}

/// `char` analyzer: raw character n-grams, no word-boundary padding.
/// Mirrors sklearn's `CountVectorizer(analyzer='char', binary=True)`.
fn extract_char_ngrams(text: &str, ngram_range: (usize, usize)) -> Vec<String> {
    let lower = text.to_lowercase();
    let bytes = lower.as_bytes();
    let mut seen = std::collections::HashSet::new();
    let mut ngrams = Vec::new();

    for n in ngram_range.0..=ngram_range.1 {
        if bytes.len() < n {
            continue;
        }
        for window in bytes.windows(n) {
            if let Ok(ngram) = std::str::from_utf8(window) {
                let s = ngram.to_string();
                if seen.insert(s.clone()) {
                    ngrams.push(s);
                }
            }
        }
    }

    ngrams
}

/// `word` analyzer: whitespace-tokenized word n-grams.
/// Mirrors sklearn's `CountVectorizer(analyzer='word', binary=True)`.
fn extract_word_ngrams(text: &str, ngram_range: (usize, usize)) -> Vec<String> {
    let lower = text.to_lowercase();
    let words: Vec<&str> = lower.split_whitespace().collect();
    let mut seen = std::collections::HashSet::new();
    let mut ngrams = Vec::new();

    for n in ngram_range.0..=ngram_range.1 {
        if words.len() < n {
            continue;
        }
        for window in words.windows(n) {
            let s = window.join(" ");
            if seen.insert(s.clone()) {
                ngrams.push(s);
            }
        }
    }

    ngrams
}

/// Legacy convenience: extract char_wb (3,5) n-grams — used by DefaultL1Scanner.
fn extract_ngrams(text: &str) -> Vec<String> {
    extract_char_wb_ngrams(text, (3, 5))
}

/// Score pre-extracted n-grams against a weight table.
fn score_ngrams(ngrams: &[String], bias: f64, weights: &phf::Map<&str, f64>) -> f64 {
    let mut score = bias;
    for ngram in ngrams {
        if let Some(&w) = weights.get(ngram.as_str()) {
            score += w;
        }
    }
    score
}

/// Score a single text against the compiled generalist weight table.
///
/// Returns bias + sum(matched weights). This is a raw SVM margin, not a probability.
/// Use `calibrate_score()` to convert to a probability.
pub fn score_text(text: &str) -> f64 {
    let ngrams = extract_ngrams(text);
    score_ngrams(&ngrams, l1_weights::BIAS, &l1_weights::WEIGHTS)
}

// ---------------------------------------------------------------------------
// L1Model adapter — bridges compiled-in SVM to the L1 harness trait
// ---------------------------------------------------------------------------

/// SVM generalist model implementing the L1Model trait.
///
/// Wraps the compiled-in generalist weight table (char_wb 3,5 n-grams)
/// behind the harness's pluggable model interface.
pub struct SvmModel;

impl L1Model for SvmModel {
    fn score(&self, text: &str) -> f64 {
        score_text(text)
    }

    fn calibration(&self) -> CalibrationParams {
        CalibrationParams { a: SIGMOID_A, b: SIGMOID_B }
    }
}

// ---------------------------------------------------------------------------
// Squash pass — O(N) de-obfuscation
// ---------------------------------------------------------------------------

/// Strip all non-alphanumeric characters and lowercase. O(N) de-obfuscation
/// that neutralizes character-level obfuscation before re-scoring:
///
/// - `"i. g-n o r e, P.R.E.V.I.O.U.S!"` → `"ignoreprevious"`
/// - `"s u d o  r m  -r f"` → `"sudormrf"`
///
/// The squashed text is re-scored against all specialists. If the squashed
/// score exceeds the raw score, the obfuscation was masking an attack.
fn squash(text: &str) -> String {
    // Lowercase first: some Unicode chars (e.g. U+0130 İ) produce
    // combining marks when lowercased, so filter alnum AFTER.
    text.chars()
        .flat_map(|c| c.to_lowercase())
        .filter(|c| c.is_alphanumeric())
        .collect()
}

// ---------------------------------------------------------------------------
// Implementation
// ---------------------------------------------------------------------------

/// Default L1 scanner using compiled-in character n-gram weights.
pub struct DefaultL1Scanner;

impl DefaultL1Scanner {
    pub fn new() -> Self {
        Self
    }
}

impl Default for DefaultL1Scanner {
    fn default() -> Self {
        Self::new()
    }
}

impl L1Scanner for DefaultL1Scanner {
    fn scan(&self, messages: &[Message], config: &L1Config) -> L1Result {
        let mut per_message_scores = Vec::new();
        let mut verdict = L1Verdict::Allow;

        for (i, msg) in messages.iter().enumerate() {
            // Skip trusted content (system prompts, developer messages).
            // L1 only scans untrusted content — user input and tool results.
            if msg.trust == TrustLevel::Trusted {
                continue;
            }

            if msg.content.is_empty() {
                continue;
            }

            let score = score_text(&msg.content);

            per_message_scores.push(L1MessageScore {
                message_index: i,
                role: msg.role.clone(),
                score,
                calibrated: calibrate_score(score),
                specialist_name: None,
            });

            // First threshold breach determines verdict, but we keep scanning.
            if verdict == L1Verdict::Allow && score >= config.threshold {
                verdict = L1Verdict::Block(L1Block {
                    reason: format!(
                        "L1 classifier score {:.3} >= threshold {:.3}",
                        score, config.threshold
                    ),
                    message_index: i,
                    role: msg.role.clone(),
                    score,
                });
            }
        }

        L1Result {
            verdict,
            per_message_scores,
        }
    }
}

