/// A specialist's compiled-in weight table with its feature extraction config.
pub struct SpecialistWeights {
    pub name: &'static str,
    pub bias: f64,
    pub threshold: f64,
    pub weights: &'static phf::Map<&'static str, f64>,
    pub analyzer: NgramAnalyzer,
    pub ngram_range: (usize, usize),
}

/// Compiled-in specialist entry: (name, bias, weights, analyzer, ngram_range).
///
/// IMPORTANT: analyzer/range MUST match what each specialist was trained with.
/// Update the entry here when retraining a specialist with a new analyzer.
///
/// Target permutations (from structural review — apply when retraining):
/// - generalist: char_wb (3,5) — broad coverage
/// - adversarial_suffix: char (3,5) — GCG gibberish has no word boundaries
/// - roleplay_jailbreak: word (2,4) — phrase-level "pretend you are"
/// - meta_probe: word (1,2) — keyword-level "system prompt"
/// - instruction_override: word (1,3) — "ignore previous instructions"
/// - exfiltration: char_wb (3,5) — URL/data patterns
/// - indirect_injection: char_wb (3,5) — embedded payload patterns
type SpecialistEntry = (
    &'static str,
    f64,
    &'static phf::Map<&'static str, f64>,
    NgramAnalyzer,
    (usize, usize),
);

/// Registry of all compiled-in specialist weight tables.
/// Add new entries here as specialists are trained.
fn compiled_specialists() -> Vec<SpecialistEntry> {
    // Current: all trained with char_wb except meta_probe (4,6).
    // Registry entries updated to new analyzer/range as each specialist is retrained.
    vec![
        (
            "generalist",
            l1_weights::BIAS,
            &l1_weights::WEIGHTS,
            NgramAnalyzer::CharWb,
            (3, 5),
        ),
        (
            "roleplay_jailbreak",
            l1_weights_roleplay_jailbreak::BIAS,
            &l1_weights_roleplay_jailbreak::WEIGHTS,
            NgramAnalyzer::Word,
            (2, 4),
        ),
        (
            "instruction_override",
            l1_weights_instruction_override::BIAS,
            &l1_weights_instruction_override::WEIGHTS,
            NgramAnalyzer::Word,
            (1, 3),
        ),
        (
            "meta_probe",
            l1_weights_meta_probe::BIAS,
            &l1_weights_meta_probe::WEIGHTS,
            NgramAnalyzer::Word,
            (1, 2),
        ),
        (
            "exfiltration",
            l1_weights_exfiltration::BIAS,
            &l1_weights_exfiltration::WEIGHTS,
            NgramAnalyzer::CharWb,
            (3, 5),
        ),
        (
            "adversarial_suffix",
            l1_weights_adversarial_suffix::BIAS,
            &l1_weights_adversarial_suffix::WEIGHTS,
            NgramAnalyzer::Char,
            (3, 5),
        ),
        (
            "indirect_injection",
            l1_weights_indirect_injection::BIAS,
            &l1_weights_indirect_injection::WEIGHTS,
            NgramAnalyzer::CharWb,
            (3, 5),
        ),
    ]
}

/// Ensemble L1 scanner: scores messages against multiple specialist classifiers.
///
/// Each specialist has its own weight table and threshold. N-grams are extracted
/// per specialist (matching its analyzer).
///
/// Routing modes:
/// - **Asymmetric** (when `generalist_solo_threshold` is Some): The generalist
///   blocks solo at high confidence; in the gray zone it needs specialist
///   corroboration. Best precision/recall tradeoff.
/// - **Flat consensus** (when `generalist_solo_threshold` is None): Block when
///   `min_agree` or more specialists breach their thresholds.
pub struct EnsembleL1Scanner {
    specialists: Vec<SpecialistWeights>,
    min_agree: usize,
    generalist_solo_threshold: Option<f64>,
}

impl EnsembleL1Scanner {
    /// Build an ensemble from config-specified specialists.
    ///
    /// Only specialists that appear in both the config and the compiled-in
    /// registry are included. Unrecognized config names are silently skipped
    /// (the weight file may not have been compiled in yet).
    pub fn new(
        config_specialists: &HashMap<String, L1SpecialistConfig>,
        min_agree: usize,
        generalist_solo_threshold: Option<f64>,
    ) -> Self {
        let mut specialists = Vec::new();
        for (name, bias, weights, analyzer, ngram_range) in compiled_specialists() {
            if let Some(spec_config) = config_specialists.get(name) {
                specialists.push(SpecialistWeights {
                    name,
                    bias,
                    threshold: spec_config.threshold,
                    weights,
                    analyzer,
                    ngram_range,
                });
            }
        }
        Self {
            specialists,
            min_agree: min_agree.max(1),
            generalist_solo_threshold,
        }
    }
}

impl EnsembleL1Scanner {
    /// Score a single text against all specialists, returning raw SVM margins.
    ///
    /// Returns Vec of (specialist_name, raw_score) in registry order.
    /// Includes squash pass: score = max(raw, squash) per specialist.
    /// Each specialist uses its own analyzer/ngram_range for extraction.
    /// Used by the eval binary to emit per-specialist score matrices
    /// for meta-classifier training.
    pub fn score_all(&self, text: &str) -> Vec<(&str, f64)> {
        let squashed = squash(text);

        self.specialists
            .iter()
            .map(|spec| {
                let ngrams = extract_ngrams_with(text, spec.analyzer, spec.ngram_range);
                let raw = score_ngrams(&ngrams, spec.bias, spec.weights);
                let sq_ngrams = extract_ngrams_with(&squashed, spec.analyzer, spec.ngram_range);
                let sq = score_ngrams(&sq_ngrams, spec.bias, spec.weights);
                (spec.name, raw.max(sq))
            })
            .collect()
    }
}

impl L1Scanner for EnsembleL1Scanner {
    fn scan(&self, messages: &[Message], _config: &L1Config) -> L1Result {
        // Thresholds come from per-specialist configs (set at construction).
        let mut per_message_scores = Vec::new();
        let mut verdict = L1Verdict::Allow;

        for (i, msg) in messages.iter().enumerate() {
            if msg.trust == TrustLevel::Trusted {
                continue;
            }
            if msg.content.is_empty() {
                continue;
            }

            // Squash once per message; n-grams extracted per specialist.
            let squashed = squash(&msg.content);

            let mut best_calibrated = 0.0_f32;
            let mut best_score = f64::NEG_INFINITY;
            let mut best_specialist: Option<&str> = None;

            // Per-specialist scores: (name, effective_score, breached_threshold)
            let mut specialist_scores: Vec<(&str, f64, bool)> =
                Vec::with_capacity(self.specialists.len());

            for specialist in &self.specialists {
                let ngrams = extract_ngrams_with(
                    &msg.content,
                    specialist.analyzer,
                    specialist.ngram_range,
                );
                let raw = score_ngrams(&ngrams, specialist.bias, specialist.weights);
                let sq_ngrams = extract_ngrams_with(
                    &squashed,
                    specialist.analyzer,
                    specialist.ngram_range,
                );
                let sq = score_ngrams(&sq_ngrams, specialist.bias, specialist.weights);
                let effective = raw.max(sq);
                let cal = calibrate_score(effective);

                if cal > best_calibrated {
                    best_calibrated = cal;
                    best_score = effective;
                    best_specialist = Some(specialist.name);
                }

                let breached = effective >= specialist.threshold;
                specialist_scores.push((specialist.name, effective, breached));
            }

            // If no specialist scored, use 0.0 (empty ensemble edge case).
            if best_specialist.is_none() {
                best_score = 0.0;
            }

            per_message_scores.push(L1MessageScore {
                message_index: i,
                role: msg.role.clone(),
                score: best_score,
                calibrated: best_calibrated,
                specialist_name: best_specialist.map(|s| s.to_string()),
            });

            // --- Routing decision ---
            if verdict != L1Verdict::Allow {
                continue; // Already blocked on an earlier message.
            }

            let block_reason = if let Some(solo_thresh) = self.generalist_solo_threshold {
                // Asymmetric routing: generalist is the anchor.
                self.asymmetric_route(&specialist_scores, solo_thresh)
            } else {
                // Flat consensus: any min_agree specialists breaching triggers block.
                self.consensus_route(&specialist_scores)
            };

            if let Some((reason, score)) = block_reason {
                verdict = L1Verdict::Block(L1Block {
                    reason,
                    message_index: i,
                    role: msg.role.clone(),
                    score,
                });
            }
        }

        L1Result {
            verdict,
            per_message_scores,
        }
    }
}

impl EnsembleL1Scanner {
    /// Asymmetric routing: generalist acts as anchor.
    ///
    /// Rule 1: generalist >= solo_threshold -> Block (high confidence, no wingman needed)
    /// Rule 2: generalist >= gen.threshold AND any non-gen specialist >= its threshold -> Block
    /// Rule 3: else -> Pass
    fn asymmetric_route(
        &self,
        scores: &[(&str, f64, bool)],
        solo_threshold: f64,
    ) -> Option<(String, f64)> {
        // Find generalist score.
        let gen = scores.iter().find(|(name, _, _)| *name == "generalist");
        let (gen_score, gen_breached) = match gen {
            Some((_, score, breached)) => (*score, *breached),
            None => return None, // No generalist in ensemble — can't route.
        };

        // Rule 1: Generalist solo block at high confidence.
        if gen_score >= solo_threshold {
            return Some((
                format!(
                    "L1 asymmetric: generalist solo {:.3} >= {:.3}",
                    gen_score, solo_threshold,
                ),
                gen_score,
            ));
        }

        // Rule 2: Generalist suspicious + any specialist corroboration.
        if gen_breached {
            for &(name, score, breached) in scores {
                if name == "generalist" {
                    continue;
                }
                if breached {
                    return Some((
                        format!(
                            "L1 asymmetric: generalist {:.3} + {} {:.3}",
                            gen_score, name, score,
                        ),
                        gen_score,
                    ));
                }
            }
        }

        // Rule 3: Pass.
        None
    }

    /// Flat consensus routing: block when >= min_agree specialists breach.
    fn consensus_route(&self, scores: &[(&str, f64, bool)]) -> Option<(String, f64)> {
        let mut breach_count = 0_usize;
        let mut top_name: Option<&str> = None;
        let mut top_score = 0.0_f64;

        for &(name, score, breached) in scores {
            if breached {
                breach_count += 1;
                if score > top_score {
                    top_name = Some(name);
                    top_score = score;
                }
            }
        }

        if breach_count >= self.min_agree {
            if let Some(name) = top_name {
                return Some((
                    format!(
                        "L1 ensemble: {}/{} specialists breached (top: {} {:.3})",
                        breach_count,
                        self.specialists.len(),
                        name,
                        top_score,
                    ),
                    top_score,
                ));
            }
        }

        None
    }
}

