    fn ensemble_config() -> (HashMap<String, L1SpecialistConfig>, L1Config) {
        let mut specialists = HashMap::new();
        // All 6 specialists frozen — production-grade at threshold 0.0
        for name in &[
            "exfiltration",
            "adversarial_suffix",
            "indirect_injection",
            "meta_probe",
            "instruction_override",
            "roleplay_jailbreak",
        ] {
            specialists.insert(
                name.to_string(),
                L1SpecialistConfig { threshold: 0.0 },
            );
        }
        let config = L1Config {
            mode: crate::config::L1Mode::Block,
            threshold: 0.0,
            min_agree: 1, // OR logic for unit tests
            generalist_solo_threshold: None,
            specialists: specialists.clone(),
        };
        (specialists, config)
    }

